import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Encode user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        // Output encoded user input to the webpage
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + encodedUserInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
